firmware_template.source:
#include "access_control.h"
#include <SPI.h>
#include <MFRC522.h>
#define MAX_CARDS 32
#define RELAY_PIN 25
static MFRC522 rfid(5,22);
static uint32_t _cards[MAX_CARDS];
static uint8_t _cnt=0;
static bool _unlocked=false;
static uint32_t _lastUid=0;
static unsigned long _unlockTime=0;
static uint32_t _getUid(){uint32_t u=0;for(byte i=0;i<rfid.uid.size;i++)u=(u<<8)|rfid.uid.uidByte[i];return u;}
void access_setup(){SPI.begin();rfid.PCD_Init();pinMode(RELAY_PIN,OUTPUT);digitalWrite(RELAY_PIN,HIGH);Serial.println("[access] OK");}
void access_loop(){if(_unlocked&&millis()-_unlockTime>5000){digitalWrite(RELAY_PIN,HIGH);_unlocked=false;}if(!rfid.PICC_IsNewCardPresent()||!rfid.PICC_ReadCardSerial())return;_lastUid=_getUid();for(uint8_t i=0;i<_cnt;i++){if(_cards[i]==_lastUid){digitalWrite(RELAY_PIN,LOW);_unlocked=true;_unlockTime=millis();Serial.printf("[access] OK uid=%08lX\n",(unsigned long)_lastUid);break;}}rfid.PICC_HaltA();}
bool access_add_card(uint32_t u){if(_cnt>=MAX_CARDS)return false;_cards[_cnt++]=u;return true;}
bool access_remove_card(uint32_t u){for(uint8_t i=0;i<_cnt;i++){if(_cards[i]==u){_cards[i]=_cards[--_cnt];return true;}}return false;}
bool access_is_unlocked(){return _unlocked;}
uint32_t access_last_uid(){return _lastUid;}
